public class TopologicalSort { public static void topologicalSort(int vertices, java.util.List<Integer>[] adj) { boolean[] visited = new boolean[vertices]; java.util.Stack<Integer> stack = new java.util.Stack<>(); for(int i = 0; i < vertices; i++) if(!visited[i]) dfs(i, visited, stack, adj); while(!stack.isEmpty()) System.out.println(stack.pop()); } public static void dfs(int v, boolean[] visited, java.util.Stack<Integer> stack, java.util.List<Integer>[] adj) { visited[v] = true; for(int neighbor : adj[v]) if(!visited[neighbor]) dfs(neighbor, visited, stack, adj); stack.push(v); } }